import { useState, useEffect } from "react";
import { getPolicies, addPolicy, updatePolicy, deletePolicy } from "../services/firestore";

export default function KnowledgeBaseForm() {
  const [policies, setPolicies] = useState([]);
  const [selectedPolicy, setSelectedPolicy] = useState(null);
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");
  const [category, setCategory] = useState("");
  const [loading, setLoading] = useState(true);

  const fetchPolicies = async () => {
    setLoading(true);
    const data = await getPolicies();
    setPolicies(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchPolicies();
  }, []);

  const handleSelectPolicy = (policy) => {
    setSelectedPolicy(policy);
    setTitle(policy.title);
    setContent(policy.content);
    setCategory(policy.category || "");
  };

  const clearForm = () => {
    setSelectedPolicy(null);
    setTitle("");
    setContent("");
    setCategory("");
  };

  const handleAddPolicy = async (e) => {
    e.preventDefault();
    if (title && content) {
      await addPolicy(title, content, category);
      fetchPolicies();
      clearForm();
    }
  };

  const handleUpdatePolicy = async (e) => {
    e.preventDefault();
    if (selectedPolicy && title && content) {
      await updatePolicy(selectedPolicy.id, title, content, category);
      fetchPolicies();
      clearForm();
    }
  };

  const handleDeletePolicy = async () => {
    if (selectedPolicy) {
      await deletePolicy(selectedPolicy.id);
      fetchPolicies();
      clearForm();
    }
  };

  return (
    <div className="space-y-6">
      <div className="card p-8">
        <h2 className="card-header mb-1">
          {selectedPolicy ? "Edit Policy" : "Add New Policy"}
        </h2>
        <p className="card-subtext mb-6">
          Create or update knowledge base articles agents can search during calls.
        </p>

        <form onSubmit={selectedPolicy ? handleUpdatePolicy : handleAddPolicy} className="space-y-4">
          <div>
            <label htmlFor="title" className="label-field">Title</label>
            <input
              type="text"
              id="title"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="input-field"
              required
            />
          </div>
          <div>
            <label htmlFor="content" className="label-field">Content</label>
            <textarea
              id="content"
              value={content}
              onChange={(e) => setContent(e.target.value)}
              rows="4"
              className="input-field resize-y"
              required
            />
          </div>
          <div>
            <label htmlFor="category" className="label-field">Category</label>
            <input
              type="text"
              id="category"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              className="input-field"
              placeholder="e.g. billing, clearance, account"
            />
          </div>
          <div className="flex justify-end gap-2 pt-2">
            {selectedPolicy && (
              <button type="button" onClick={handleDeletePolicy} className="btn-danger">
                Delete
              </button>
            )}
            <button type="button" onClick={clearForm} className="btn-secondary">
              Clear
            </button>
            <button type="submit" className="btn-primary px-6">
              {selectedPolicy ? "Update Policy" : "Add Policy"}
            </button>
          </div>
        </form>
      </div>

      <div className="card p-8">
        <h3 className="card-header mb-4">Existing Policies ({policies.length})</h3>

        {loading ? (
          <p className="text-brand-slate">Loading policies...</p>
        ) : policies.length === 0 ? (
          <p className="text-brand-slate">No policies in the knowledge base yet.</p>
        ) : (
          <ul className="space-y-2">
            {policies.map((policy) => (
              <li
                key={policy.id}
                onClick={() => handleSelectPolicy(policy)}
                className={`p-4 rounded-input cursor-pointer border transition-all ${
                  selectedPolicy?.id === policy.id
                    ? "border-brand-navy bg-brand-bg"
                    : "border-brand-border hover:bg-brand-bg"
                }`}
              >
                <p className="font-extrabold text-brand-navy">{policy.title}</p>
                {policy.category && (
                  <span className="inline-block mt-1 text-xs font-bold text-brand-slate bg-brand-bg px-2 py-0.5 rounded-full">
                    {policy.category}
                  </span>
                )}
                <p className="text-sm text-brand-slate mt-2 line-clamp-2">{policy.content}</p>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
}
